package com.nexra.hrms.nexra.modules.hrms.performance.security;
import com.nexra.hrms.nexra.modules.hrms.performance.config.PerformanceProperties; import io.jsonwebtoken.*; import io.jsonwebtoken.security.Keys; import java.nio.charset.StandardCharsets; import java.util.*; import javax.crypto.SecretKey; import lombok.RequiredArgsConstructor; import org.springframework.stereotype.Service;
@Service @RequiredArgsConstructor public class PerformanceJwtService { private final PerformanceProperties properties; public AuthenticatedPerformanceUser parseBearerToken(final String token){ Claims c=Jwts.parser().verifyWith(signingKey()).build().parseSignedClaims(token).getPayload(); @SuppressWarnings("unchecked") List<String> roles=c.get("roles", List.class); return new AuthenticatedPerformanceUser(UUID.fromString(c.get("uid", String.class)), c.getSubject(), c.get("tenant", String.class), roles==null?Set.of():Set.copyOf(roles)); } private SecretKey signingKey(){ byte[] b=properties.getSecurity().getJwtSecret().getBytes(StandardCharsets.UTF_8); if(b.length<32) throw new IllegalStateException("app.performance.security.jwt-secret must be at least 32 bytes"); return Keys.hmacShaKeyFor(b);} }

